create table "_Symbol"
(
    "Id"              integer generated by default as identity
        constraint "_Symbol_pk"
            primary key,
    "CategoryId"      integer                                                not null,
    "Type"            integer                                                not null,
    "CreatedOn"       timestamp with time zone default now()                 not null,
    "Code"            varchar(20)                                            not null,
    "Category"        varchar(100)             default ''::character varying not null,
    "OperatorPartyId" bigint                   default 1                     not null
        references core."_Party"
);

alter table "_Symbol"
    owner to bcrpro;

create index "IX__Symbol_CategoryId"
    on "_Symbol" ("CategoryId");

create index "IX__Symbol_Code"
    on "_Symbol" ("Code");

create index "IX__Symbol_OperatorPartyId"
    on "_Symbol" ("OperatorPartyId");

create index "IX__Symbol_Category"
    on "_Symbol" ("Category");

grant select on "_Symbol" to dev_read;

